PROCEDURE DirectRead(fileHandle, recordNumber, recordSize)
  BEGIN
    // Calculate physical byte offset from start of file
    offset = recordNumber * recordSize

    // Seek to the calculated position
    Seek(fileHandle, offset)

    // Read the record directly
    record = ReadRecord(fileHandle)

    RETURN record
  END

// Example: To read 5th record with record size 100 bytes
// offset = 5 * 100 = 500 bytes from start
// Seek to position 500, then read

// Time Complexity: O(1) - constant time access
// Space Complexity: O(1)

PROCEDURE IndexedRead(fileHandle, indexBlock, recordNumber, blockSize)
  BEGIN
    // Calculate which data block contains the record
    blockNumber = recordNumber / recordsPerBlock

    // Step 1: Read the index block
    indexTable = ReadBlock(fileHandle, indexBlock)

    // Step 2: Get pointer to data block from index
    dataBlockPointer = indexTable[blockNumber]

    // Step 3: Read the actual data block
    dataBlock = ReadBlock(fileHandle, dataBlockPointer)

    // Step 4: Extract specific record from block
    offsetInBlock = recordNumber % recordsPerBlock
    record = ExtractRecord(dataBlock, offsetInBlock)

    RETURN record
  END

// Time Complexity: O(1) for index read + O(1) for data read = O(1)
// Space Complexity: O(1) for index table + O(blockSize) for data
